from flask import Flask, request
from pymemcache.client.base import Client
from flask_sqlalchemy import SQLAlchemy
from functools import wraps

app = Flask(__name__)
db = SQLAlchemy(app)
client = Client(('localhost', 11211))

# Decorator for API responses caching
def cache_API_response(ttl):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            response = client.get(request.path)
            if response is None:
                response = f(*args, **kwargs)
                client.set(request.path, response, expire=ttl)
            return response
        return decorated_function
    return decorator

# Function for DB queries caching
def cache_db_query(query, ttl):
    result = client.get(query)
    if result is None:
        result = db.session.execute(query).fetchall()
        client.set(query, result, expire=ttl)
    return result

@app.route('/api/data', methods=["GET"])
@cache_API_response(300)
def get_data():
    # Assuming data is fetched from a database
    query = "SELECT * FROM data_table"
    data = cache_db_query(query, 300)
    return {"data": data}